      bot := bot - 1;
    }
  }
  if !botDone {
    assert forall r | 0 <= r < n :: forall c | 0 <= c < |grid[r]| :: grid[r][c] != '*';
    assert false;
    result := []; return;
  }
  var bottom := bot + 1;

  // top <= bot because row top has a star but rows > bot don't
